import React, { Fragment, useState, useEffect } from 'react';
import { Col, Card, CardHeader, CardBody, Form, Row } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Btn, Breadcrumbs, H4 } from '../../../AbstractElements';
import { Link, useNavigate } from 'react-router-dom';
import { getClientUrlDataToken } from '../../../Utils/restUtils';
import { Search, Filter } from '../../../Constant';
import { useSelector } from 'react-redux';
import Transparentspinner from '../../Common/Loader/Transparentspinner';

const CustomMessageList = () => {
    const authState = useSelector((state) => state.auth);
    const [messageList, setMessageList] = useState([]);
    const [searchKeyword, setSearchKeyword] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const mockData = [
        {
            id: 1,
            service_type: 'WhatsApp',
            recipient_type: 'Customer',
            reason: 'Maintenance Alert',
            details: 'Dear Customer, our services will be temporarily down for scheduled maintenance on Sunday from 2 AM to 4 AM.',
            created_at: '2026-05-20 10:30 AM'
        },
        {
            id: 2,
            service_type: 'SMS',
            recipient_type: 'Area',
            reason: 'Network Upgrade',
            details: 'Service upgrade completed successfully in your area. Thank you for your patience.',
            created_at: '2026-05-19 04:15 PM'
        }
    ];

    const fetchMessages = async () => {
        setLoading(true);
        try {
            const url = authState.userRole === 1 ? '/admin/get-custom-messages' : '/get-custom-messages';
            const data = await getClientUrlDataToken(authState.apiUrl, url);
            if (data.status === true && Array.isArray(data.data)) {
                setMessageList(data.data);
            } else if (data.status === 404 || data.status === undefined) {
                // Fallback simulation for non-implemented backend list endpoint
                setMessageList(mockData);
            } else {
                handleApiErrorStatus(data.status);
            }
        } catch (err) {
            console.error("Error fetching message logs:", err);
            setMessageList(mockData);
        } finally {
            setLoading(false);
        }
    };

    const handleApiErrorStatus = (status) => {
        if (status >= 400 && status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (status >= 500 && status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    useEffect(() => {
        fetchMessages();
    }, []);

    const handleSearchInputChange = (event) => {
        setSearchKeyword(event.target.value);
    };

    const handleFilterSubmit = (event) => {
        event.preventDefault();
        fetchMessages();
    };

    const filteredData = messageList.filter(item => {
        const keyword = searchKeyword.toLowerCase();
        return (
            item.service_type?.toLowerCase().includes(keyword) ||
            item.recipient_type?.toLowerCase().includes(keyword) ||
            item.reason?.toLowerCase().includes(keyword) ||
            item.details?.toLowerCase().includes(keyword)
        );
    });

    const columns = [
        {
            name: <H4>Sl.No</H4>,
            selector: (row, index) => index + 1,
            width: '70px',
            center: true,
        },
        {
            name: <H4>Service Type</H4>,
            selector: (row) => row.service_type,
            sortable: true,
            width: '150px',
        },
        {
            name: <H4>Recipient Type</H4>,
            selector: (row) => row.recipient_type,
            sortable: true,
            width: '150px',
        },
        {
            name: <H4>Reason</H4>,
            selector: (row) => row.reason,
            sortable: true,
            wrap: true,
            width: '200px',
        },
        {
            name: <H4>Details</H4>,
            selector: (row) => row.details,
            sortable: true,
            wrap: true,
            grow: 2,
        },
        {
            name: <H4>Sent At</H4>,
            selector: (row) => row.created_at,
            sortable: true,
            width: '180px',
        }
    ];

    return (
        <Fragment>
            {loading && <Transparentspinner />}
            <Breadcrumbs mainTitle="Custom Message" parent="Settings" title="Custom Message" />
            <Card className='cardWidth'>
                <CardHeader style={{ margin: '-5px 0 -20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <H3>Custom Messages</H3>
                    <div>
                        <Link to={`${process.env.PUBLIC_URL}/settings/custom-message-send`} className="btn btn-primary">Send Custom Message</Link>
                    </div>
                </CardHeader>

                <CardBody>
                    <span className='custom-span'>
                        <Form className="needs-validation" noValidate onSubmit={handleFilterSubmit}>
                            <Row className="ps-3 mb-4 custom-search-filter align-items-center">
                                <Col xs="6" sm="4" md="2" lg="2">
                                    <input
                                        className="form-control"
                                        placeholder={Search}
                                        type="text"
                                        value={searchKeyword}
                                        onChange={handleSearchInputChange}
                                    />
                                </Col>
                                <Col xs="6" sm="6" md="4" lg="3">
                                    <Btn className="custom-filter-btn" attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                                </Col>
                            </Row>
                        </Form>
                    </span>
                    <div className="order-history table-responsive">
                        <DataTable
                            data={filteredData}
                            columns={columns}
                            pagination
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            fixedHeader
                            style={{ border: '1px solid' }}
                        />
                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default CustomMessageList;